const cellKey = ([x, y]: Cell): string => `${x},${y}`;

const deadNeighborsOf = (cell: Cell): Cell[] => {
  const [x, y] = cell;
  const result: Cell[] = [];
  for (let dx = -1; dx <= 1; dx++) {
    for (let dy = -1; dy <= 1; dy++) {
      if (dx !== 0 || dy !== 0) result.push([x + dx, y + dy]);
    }
  }
  return result;
};

export function nextGeneration(cells: Cell[]): Cell[] {
  const survivors = cells.filter((cell) => survives(countLiveNeighbors(cell, cells)));
  const liveSet = new Set(cells.map(cellKey));
  const candidates = new Map<string, Cell>();
  for (const cell of cells) {
    for (const neighbor of deadNeighborsOf(cell)) {
      const key = cellKey(neighbor);
      if (!liveSet.has(key)) candidates.set(key, neighbor);
    }
  }
  const births: Cell[] = [];
  for (const candidate of candidates.values()) {
    if (countLiveNeighbors(candidate, cells) === 3) births.push(candidate);
  }
  return [...survivors, ...births];
}
